-- {"operators": "INNER_JOIN,FILTER,PROJECTION", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": true, "tables": "ORDER_LINE,ITEM,STOCK,WAREHOUSE"}
SELECT ol.OL_W_ID, ol.OL_D_ID, ol.OL_O_ID, ol.OL_NUMBER, ol.OL_I_ID, ol.OL_AMOUNT, CASE WHEN ol.OL_AMOUNT > 100 THEN 'high' WHEN ol.OL_AMOUNT > 50 THEN 'medium' ELSE 'low' END AS amount_tier, CASE WHEN ol.OL_QUANTITY >= 10 THEN 'bulk' WHEN ol.OL_QUANTITY >= 5 THEN 'multi' ELSE 'single' END AS qty_category, CASE WHEN s.S_QUANTITY < 5 THEN 'critical' WHEN s.S_QUANTITY < 20 THEN 'low' WHEN s.S_QUANTITY < 50 THEN 'medium' ELSE 'ok' END AS stock_status, i.I_PRICE, i.I_PRICE * ol.OL_QUANTITY AS line_value, CASE WHEN i.I_PRICE > 80 THEN 'premium' WHEN i.I_PRICE > 40 THEN 'mid' ELSE 'standard' END AS price_tier, CASE WHEN ol.OL_AMOUNT > i.I_PRICE * ol.OL_QUANTITY THEN 'discounted' ELSE 'full_price' END AS pricing_mode, w.W_TAX, ol.OL_AMOUNT * (1 + w.W_TAX) AS taxed_amount, CASE WHEN w.W_TAX > 0.1 THEN 'high_tax' ELSE 'low_tax' END AS tax_band, s.S_YTD, s.S_ORDER_CNT, CASE WHEN s.S_REMOTE_CNT > s.S_ORDER_CNT / 2 THEN 'mostly_remote' ELSE 'local' END AS supply_mode FROM ORDER_LINE ol JOIN ITEM i ON ol.OL_I_ID = i.I_ID JOIN STOCK s ON ol.OL_W_ID = s.S_W_ID AND ol.OL_I_ID = s.S_I_ID JOIN WAREHOUSE w ON ol.OL_W_ID = w.W_ID WHERE ol.OL_AMOUNT > 0 AND i.I_PRICE > 0 AND s.S_QUANTITY >= 0 AND w.W_TAX >= 0;
